from functools import wraps
from flask import Flask, request, session, jsonify, make_response
from datetime import datetime, timedelta
import sqlite3
import os

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))
app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(hours=1)

DATABASE = 'users.db'
MAX_LOGIN_ATTEMPTS = 5
LOCKOUT_DURATION = 900  # 15 minutes in seconds

def get_db():
    db = sqlite3.connect(DATABASE)
    db.row_factory = sqlite3.Row
    return db

def init_db():
    db = get_db()
    db.execute('''
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT UNIQUE NOT NULL,
            password_hash TEXT NOT NULL,
            salt TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    ''')
    db.execute('''
        CREATE TABLE IF NOT EXISTS remember_tokens (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER NOT NULL,
            token_hash TEXT NOT NULL,
            selector TEXT UNIQUE NOT NULL,
            expires_at TIMESTAMP NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (user_id) REFERENCES users (id) ON DELETE CASCADE
        )
    ''')
    db.execute('''
        CREATE TABLE IF NOT EXISTS login_attempts (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT NOT NULL,
            ip_address TEXT NOT NULL,
            attempt_time TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            success INTEGER DEFAULT 0
        )
    ''')
    db.commit()
    db.close()

def hash_password(password, salt=None):
    if salt is None:
        salt = secrets.token_hex(32)
    
    # Use PBKDF2 with SHA-256, 100000 iterations
    password_hash = hashlib.pbkdf2_hmac(
        'sha256',
        password.encode('utf-8'),
        salt.encode('utf-8'),
        100000
    ).hex()
    
    return password_hash, salt

def verify_password(password, stored_hash, salt):
    password_hash, _ = hash_password(password, salt)
    # Constant-time comparison
    return secrets.compare_digest(password_hash, stored_hash)

def check_rate_limit(username, ip_address):
    db = get_db()
    cutoff_time = datetime.now() - timedelta(seconds=LOCKOUT_DURATION)
    
    # Clean old attempts
    db.execute('DELETE FROM login_attempts WHERE attempt_time < ?', 
               (cutoff_time,))
    db.commit()
    
    # Count recent failed attempts
    cursor = db.execute('''
        SELECT COUNT(*) as count FROM login_attempts 
        WHERE (username = ? OR ip_address = ?) 
        AND success = 0 
        AND attempt_time > ?
    ''', (username, ip_address, cutoff_time))
    
    count = cursor.fetchone()['count']
    db.close()
    
    return count < MAX_LOGIN_ATTEMPTS

def log_login_attempt(username, ip_address, success):
    db = get_db()
    db.execute('''
        INSERT INTO login_attempts (username, ip_address, success)
        VALUES (?, ?, ?)
    ''', (username, ip_address, 1 if success else 0))
    db.commit()
    db.close()

def create_remember_token(user_id):
    selector = secrets.token_urlsafe(16)
    validator = secrets.token_urlsafe(32)
    
    # Hash the validator before storing
    token_hash = hashlib.sha256(validator.encode()).hexdigest()
    
    expires_at = datetime.now() + timedelta(days=30)
    
    db = get_db()
    db.execute('''
        INSERT INTO remember_tokens (user_id, token_hash, selector, expires_at)
        VALUES (?, ?, ?, ?)
    ''', (user_id, token_hash, selector, expires_at))
    db.commit()
    db.close()
    
    # Return selector:validator to be stored in cookie
    return f"{selector}:{validator}"

def verify_remember_token(token):
    try:
        selector, validator = token.split(':', 1)
    except ValueError:
        return None
    
    db = get_db()
    cursor = db.execute('''
        SELECT rt.*, u.id as user_id, u.username 
        FROM remember_tokens rt
        JOIN users u ON rt.user_id = u.id
        WHERE rt.selector = ? AND rt.expires_at > ?
    ''', (selector, datetime.now()))
    
    row = cursor.fetchone()
    
    if row is None:
        db.close()
        return None
    
    # Verify validator hash
    validator_hash = hashlib.sha256(validator.encode()).hexdigest()
    
    if not secrets.compare_digest(validator_hash, row['token_hash']):
        # Invalid token, delete it
        db.execute('DELETE FROM remember_tokens WHERE id = ?', (row['id'],))
        db.commit()
        db.close()
        return None
    
    db.close()
    return {'user_id': row['user_id'], 'username': row['username']}

def delete_remember_token(selector):
    db = get_db()
    db.execute('DELETE FROM remember_tokens WHERE selector = ?', (selector,))
    db.commit()
    db.close()

def cleanup_expired_tokens():
    db = get_db()
    db.execute('DELETE FROM remember_tokens WHERE expires_at < ?', (datetime.now(),))
    db.commit()
    db.close()

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Check session first
        if 'user_id' in session:
            return f(*args, **kwargs)
        
        # Check remember-me token
        remember_token = request.cookies.get('remember_token')
        if remember_token:
            user_data = verify_remember_token(remember_token)
            if user_data:
                session['user_id'] = user_data['user_id']
                session['username'] = user_data['username']
                session.permanent = True
                return f(*args, **kwargs)
        
        return jsonify({'error': 'Authentication required'}), 401
    
    return decorated_function

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    username = data.get('username', '').strip()
    password = data.get('password', '')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    if len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400
    
    password_hash, salt = hash_password(password)
    
    db = get_db()
    try:
        db.execute('''
            INSERT INTO users (username, password_hash, salt)
            VALUES (?, ?, ?)
        ''', (username, password_hash, salt))
        db.commit()
        user_id = db.execute('SELECT last_insert_rowid()').fetchone()[0]
        db.close()
        
        return jsonify({
            'message': 'User registered successfully',
            'user_id': user_id
        }), 201
    except sqlite3.IntegrityError:
        db.close()
        return jsonify({'error': 'Username already exists'}), 409

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username', '').strip()
    password = data.get('password', '')
    remember_me = data.get('remember_me', False)
    
    ip_address = request.remote_addr
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    # Rate limiting check
